namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings

<nav class="settings-sidebar">
    <h4 class="sidebar-title">Settings</h4>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span class="sidebar-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models

<div class="settings-section">
    <h3>Profile</h3>

    @if (Profile is null)
    {
        <p>Loading profile...</p>
        return;
    }

    <div class="avatar-preview">
        @if (!string.IsNullOrWhiteSpace(AvatarUrl))
        {
            <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
        }
        else
        {
            <div class="avatar-placeholder">👤</div>
        }
        <div class="avatar-url-display">
            <label>Avatar URL</label>
            <input type="text" class="form-control" value="@AvatarUrl" readonly />
        </div>
    </div>

    <div class="form-group">
        <label for="displayName">Display Name</label>
        <input id="displayName" type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="form-group">
        <label for="email">Email</label>
        <input id="email" type="email" class="form-control" @bind="Email" />
    </div>

    <div class="form-group">
        <label for="bio">Bio</label>
        <textarea id="bio" class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Changes")
        </button>
        <button class="btn btn-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>

    @if (_showSuccess)
    {
        <div class="toast-message success">Profile saved successfully!</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_saving)
        {
            LoadFromProfile(Profile);
        }
    }

    private void LoadFromProfile(UserProfile profile)
    {
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        StateHasChanged();
        _ = HideToastAsync();
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
    }
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models

<div class="settings-section">
    <h3>Notifications</h3>

    @if (Prefs is null)
    {
        <p>Loading notification preferences...</p>
        return;
    }

    <div class="toggle-group">
        <label class="toggle-row">
            <span>Email Notifications</span>
            <input type="checkbox" class="form-check-input toggle-switch" @bind="_emailNotifications" />
        </label>
        <label class="toggle-row">
            <span>Push Notifications</span>
            <input type="checkbox" class="form-check-input toggle-switch" @bind="_pushNotifications" />
        </label>
        <label class="toggle-row">
            <span>Weekly Digest</span>
            <input type="checkbox" class="form-check-input toggle-switch" @bind="_weeklyDigest" />
        </label>
    </div>

    @if (AvailableChannels.Count > 0)
    {
        <div class="channels-section">
            <h5>Muted Channels</h5>
            @foreach (var channel in AvailableChannels)
            {
                <label class="channel-row">
                    <input type="checkbox"
                           class="form-check-input"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                    <span>@channel</span>
                </label>
            }
        </div>
    }

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Preferences")
        </button>
    </div>

    @if (_showSuccess)
    {
        <div class="toast-message success">Preferences saved successfully!</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public List<string> AvailableChannels { get; set; } = [];
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        StateHasChanged();
        _ = HideToastAsync();
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings

<div class="expandable-panel">
    <button class="panel-header" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPw">Current Password</label>
                <input id="currentPw" type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="form-group">
                <label for="newPw">New Password</label>
                <input id="newPw" type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="form-group">
                <label for="confirmPw">Confirm New Password</label>
                <input id="confirmPw" type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="toast-message error">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="toast-message success">Password updated successfully!</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _error;
    private bool _saving;
    private bool _showSuccess;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New passwords do not match.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _showSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _ = HideToastAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models

<div class="sessions-section">
    <h5>Active Sessions</h5>

    @if (Sessions.Count == 0)
    {
        <p>No active sessions.</p>
    }
    else
    {
        <table class="table sessions-table">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session.Id != CurrentSessionId)
                            {
                                <button class="btn btn-sm btn-danger"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-success">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation>
                <h5>Revoke Session</h5>
                <p>
