@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models

<div class="sessions-section">
    <h5>Active Sessions</h5>

    @if (Sessions.Count == 0)
    {
        <p>No active sessions.</p>
    }
    else
    {
        <table class="table sessions-table">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr>
                        <td>@session.Device</td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session.Id != CurrentSessionId)
                            {
                                <button class="btn btn-sm btn-danger"
                                        @onclick="() => PromptRevoke(session)">
                                    Revoke
                                </button>
                            }
                            else
                            {
                                <span class="badge bg-success">Current</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (_sessionToRevoke is not null)
    {
        <div class="modal-backdrop" @onclick="CancelRevoke">
            <div class="confirm-dialog" @onclick:stopPropagation>
                <h5>Revoke Session</h5>
                <p>
                    Are you sure you want to revoke the session on
                    <strong>@_sessionToRevoke.Device</strong>
                    from <strong>@_sessionToRevoke.Location</strong>?
                </p>
                <div class="button-group">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @(_revoking ? "Revoking..." : "Revoke")
                    </button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke" disabled="@_revoking">
                        Cancel
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models

<div class="settings-section">
    <h3>Security</h3>

    @if (Security is null)
    {
        <p>Loading security settings...</p>
        return;
    }

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="two-factor-section">
        <h5>Two-Factor Authentication</h5>
        <div class="toggle-row">
            <span>
                Two-Factor Authentication
                @if (Security.TwoFactorEnabled)
                {
                    <span class="badge bg-success">Enabled</span>
                }
                else
                {
                    <span class="badge bg-warning text-dark">Disabled</span>
                }
            </span>
            <input type="checkbox" class="form-check-input toggle-switch"
                   checked="@Security.TwoFactorEnabled" disabled />
        </div>
        @if (Security.LastPasswordChange.HasValue)
        {
            <p class="text-muted">
                Last password change: @Security.LastPasswordChange.Value.ToString("f")
            </p>
        }
    </div>

    <ActiveSessionsTable Sessions="Security.Sessions"
                         CurrentSessionId="@CurrentSessionId"
                         OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings? Security { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
}

@namespace sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models

<div class="settings-section">
    <h3>Appearance</h3>

    @if (Settings is null)
    {
        <p>Loading appearance settings...</p>
        return;
    }

    <div class="form-group">
        <label><strong>Theme</strong></label>
        <div class="radio-group">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <label class="radio-option">
                    <input type="radio" name="theme" value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <span>@theme</span>
                </label>
            }
        </div>
    </div>

    <div class="form-group">
        <label><strong>Font Size</strong></label>
        <div class="radio-group">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <label class="radio-option">
                    <input type="radio" name="fontSize" value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <span>@size</span>
                </label>
            }
        </div>
    </div>

    <div class="form-group">
        <label for="language"><strong>Language</strong></label>
        <select id="language" class="form-control" @bind="_language">
            <option value="en">English</option>
            <option value="es">Español</option>
            <option value="fr">Français</option>
            <option value="de">Deutsch</option>
            <option value="ja">日本語</option>
            <option value="zh">中文</option>
        </select>
    </div>

    <div class="toggle-row">
        <span><strong>Compact Mode</strong></span>
        <input type="checkbox" class="form-check-input toggle-switch" @bind="_compactMode" />
    </div>

    <div class="live-preview @GetPreviewClasses()">
        <h5>Live Preview</h5>
        <p>This is how your content will look with the selected settings.</p>
        <div class="preview-card">
            <strong>Sample Card</strong>
            <p>The quick brown fox jumps over the lazy dog.</p>
        </div>
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save")
        </button>
    </div>

    @if (_showSuccess)
    {
        <div class="toast-message success">Appearance settings saved!</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;
    private bool _showSuccess;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = $"preview-theme-{_theme.ToLowerInvariant()} preview-font-{_fontSize.ToLowerInvariant()}";
        if (_compactMode) classes += " preview-compact";
        return classes;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _showSuccess = true;
        StateHasChanged();
        _ = HideToastAsync();
    }

    private async Task HideToastAsync()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

