+    {
+        <div class="toast-message success">Appearance settings saved!</div>
+    }
+</div>
+
+@code {
+    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
+    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }
+
+    private string _theme = "System";
+    private string _fontSize = "Medium";
+    private string _language = "en";
+    private bool _compactMode;
+    private bool _saving;
+    private bool _showSuccess;
+
+    protected override void OnParametersSet()
+    {
+        if (Settings is not null && !_saving)
+        {
+            _theme = Settings.Theme;
+            _fontSize = Settings.FontSize;
+            _language = Settings.Language;
+            _compactMode = Settings.CompactMode;
+        }
+    }
+
+    private string GetPreviewClasses()
+    {
+        var classes = $"preview-theme-{_theme.ToLowerInvariant()} preview-font-{_fontSize.ToLowerInvariant()}";
+        if (_compactMode) classes += " preview-compact";
+        return classes;
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+        await OnSave.InvokeAsync(updated);
+        _saving = false;
+        _showSuccess = true;
+        StateHasChanged();
+        _ = HideToastAsync();
+    }
+
+    private async Task HideToastAsync()
+    {
+        await Task.Delay(3000);
+        _showSuccess = false;
+        await InvokeAsync(StateHasChanged);
+    }
+}
