    private string _activeSection = "Profile";
    private string _currentSessionId = "current";

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    private List<string> _availableChannels =
        ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        await Task.WhenAll(
            LoadProfileAsync(),
            LoadNotificationsAsync(),
            LoadSecurityAsync(),
            LoadAppearanceAsync());
