toolArgs.file_text:
@page "/settings"
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Components.Pages.Settings
@using sv_2d770a4ddaea442e870f4d4f1da1a8af.Models
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionSelected="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection Profile="_profile" OnSave="SaveProfileAsync" />
                break;
            case "Notifications":
                <NotificationsSection Prefs="_notificationPrefs"
                                      AvailableChannels="_availableChannels"
                                      OnSave="SaveNotificationsAsync" />
                break;
            case "Security":
                <SecuritySection Security="_securitySettings"
                                 CurrentSessionId="@_currentSessionId"
                                 OnChangePassword="ChangePasswordAsync"
                                 OnRevokeSession="RevokeSessionAsync" />
                break;
            case "Appearance":
                <AppearanceSection Settings="_appearanceSettings"
                                   OnSave="SaveAppearanceAsync" />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private string _currentSessionId = "current";

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    private List<string> _availableChannels =
        ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        await Task.WhenAll(
            LoadProfileAsync(),
            LoadNotificationsAsync(),
            LoadSecurityAsync(),
            LoadAppearanceAsync());
    }

    private async Task LoadProfileAsync() =>
        _profile = await SettingsService.GetProfileAsync();

    private async Task LoadNotificationsAsync() =>
        _notificationPrefs = await SettingsService.GetNotificationPrefsAsync();

    private async Task LoadSecurityAsync() =>
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();

    private async Task LoadAppearanceAsync() =>
        _appearanceSettings = await SettingsService.GetAppearanceAsync();

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        await LoadSecurityAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        await LoadSecurityAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
    }
}

